impl Server {
    /// Display all registered handlers
    pub fn display_capabilities(&self) {
        let renderer = HandlerRegistryRenderer::new(
            self.theme.clone(),
            self.context.clone()
        );

        let capabilities = self.capabilities();
        renderer.render(&capabilities, &self.console);
    }

    /// Display compact summary
    pub fn display_capabilities_summary(&self) {
        let renderer = HandlerRegistryRenderer::new(
            self.theme.clone(),
            self.context.clone()
        );

        let capabilities = self.capabilities();
        renderer.render_summary(&capabilities, &self.console);
    }
}
